import React, { useState, useRef, useEffect } from 'react';
import axios from '../api/axios'; // Or use native fetch if axios isn't configured for standard paths
import '../App.css'; // Add styling here or rely on existing vars

export default function ChatbotWidget() {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState([
        { sender: 'bot', text: 'Hi! I am the ParkSense AI Assistant. How can I help you regarding parking today?' }
    ]);
    const [input, setInput] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const endOfMessagesRef = useRef(null);

    const toggleChat = () => setIsOpen(!isOpen);

    const scrollToBottom = () => {
        endOfMessagesRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        if(isOpen) {
            scrollToBottom();
        }
    }, [messages, isOpen, isTyping]);

    const handleSend = async (e) => {
        if(e) e.preventDefault();
        if (!input.trim()) return;

        const userMsg = input.trim();
        setMessages(prev => [...prev, { sender: 'user', text: userMsg }]);
        setInput('');
        setIsTyping(true);

        try {
            // Using standard fetch just in case axios interceptors block unauthenticated calls
            const response = await fetch('http://localhost:5000/api/chatbot/query', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ query: userMsg })
            });
            const data = await response.json();

            setMessages(prev => [...prev, { sender: 'bot', text: data.reply }]);
        } catch (error) {
            setMessages(prev => [...prev, { sender: 'bot', text: "Sorry, I am having trouble connecting to the server. Please try again later." }]);
        } finally {
            setIsTyping(false);
        }
    };

    return (
        <div className="chatbot-wrapper">
            {isOpen && (
                <div className="chat-window">
                    <div className="chat-header">
                        <div style={{display: 'flex', alignItems: 'center', gap: '10px'}}>
                           <i className="fa-solid fa-robot" style={{fontSize: '1.2rem'}}></i>
                           <strong style={{fontSize: '1.1rem'}}>ParkSense AI</strong>
                        </div>
                        <button onClick={toggleChat} className="chat-close-btn"><i className="fa-solid fa-times"></i></button>
                    </div>

                    <div className="chat-body">
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`chat-message ${msg.sender}`}>
                                <div className="chat-bubble">
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                        {isTyping && (
                            <div className="chat-message bot">
                                <div className="chat-bubble typing">
                                    <span className="dot"></span><span className="dot"></span><span className="dot"></span>
                                </div>
                            </div>
                        )}
                        <div ref={endOfMessagesRef} />
                    </div>

                    <form className="chat-input-area" onSubmit={handleSend}>
                        <input 
                            type="text" 
                            placeholder="Ask about availability, price, etc..." 
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                        />
                        <button type="submit" disabled={!input.trim() || isTyping}>
                            <i className="fa-solid fa-paper-plane"></i>
                        </button>
                    </form>
                </div>
            )}

            {!isOpen && (
                <button className="chat-fab" onClick={toggleChat}>
                    <i className="fa-solid fa-comment-dots fa-lg"></i>
                </button>
            )}
        </div>
    );
}
